import { useState } from "react";
import Button from "../../components/Login/Button";
import Input from "../../components/Login/Input";
import TextButton from "../../components/Login/TextButton";
import classes from "./Login.module.css";

const Login = () => {
  const [enteredEmail, setEnteredEmail] = useState("");
  const [enteredPassword, setEnteredPassword] = useState("");
  let hasError = false;

  console.log(hasError);
  const emailChangeHandler = (event) => {
    setEnteredEmail(event.target.value);
  };

  const passwordChangeHandler = (event) => {
    setEnteredPassword(event.target.value);
  };

  const onSubmitHandler = (event) => {
    event.preventDefault();

    let emailIsValid = enteredEmail.includes("@");
    let passwordIsValid = enteredPassword.trim() !== "";
    hasError = !emailIsValid && !passwordIsValid;
  };

  return (
    <div className={classes["wrapper"]}>
      <form className={classes["form"]} onSubmit={onSubmitHandler}>
        <div className={classes["header"]}>
          <h1 className={classes["heading"]}>Welcome back!</h1>
          <div className={classes["header-text"]}>
            We're so excited to see you again!
          </div>
        </div>
        <div className={classes["block"]}>
          <Input
            name="email"
            label="email"
            type="text"
            onChange={emailChangeHandler}
            value={enteredEmail}
          ></Input>
          <Input
            name="password"
            label="password"
            type="password"
            onChange={passwordChangeHandler}
            value={enteredPassword}
          ></Input>
          <Button>Log In</Button>
          <div>
            <span className={classes["text"]}>Need an account?</span>
            <TextButton>Register</TextButton>
          </div>
        </div>
      </form>
    </div>
  );
};

export default Login;
